// // This module provides a synchronous block RAM with 1024 words, each 32 bits wide. It supports read and write operations based on a clock signal. When the chip enable (ce) input is deasserted, a write operation occurs if the write enable (we) input is high, storing the 32-bit input data (d) at the specified address (addr). If we is low, it retrieves the data from the specified address and outputs it to (q). This design serves to provide a simple memory unit suitable for applications requiring temporary data storage and retrieval.
module top_module(
    input [9:0] addr,
    input ce,
    input [31:0] d,
    input we,
    input clk,
    output reg [31:0] q
);parameter MEM_SIZE = 1024;
    reg [31:0] mem [MEM_SIZE-1:0];

    always @(posedge clk) begin
        if (ce) begin
            if (we) begin
                mem[addr] <= d;
            end else begin
                q <= mem[addr];
            end
        end
    end

endmodule
